package com.finance.tracker.security;
import jakarta.servlet.*; import jakarta.servlet.http.*; import java.io.IOException; import org.springframework.security.authentication.UsernamePasswordAuthenticationToken; import org.springframework.security.core.context.SecurityContextHolder; import org.springframework.security.web.authentication.WebAuthenticationDetailsSource; import org.springframework.web.filter.OncePerRequestFilter; import org.springframework.stereotype.Component;
@Component public class JwtAuthenticationFilter extends OncePerRequestFilter {
 private final JwtService jwt; private final CustomUserDetailsService users; public JwtAuthenticationFilter(JwtService jwt,CustomUserDetailsService users){this.jwt=jwt;this.users=users;}
 @Override protected void doFilterInternal(HttpServletRequest req,HttpServletResponse res,FilterChain chain)throws ServletException,IOException {String h=req.getHeader("Authorization"); if(h!=null&&h.startsWith("Bearer ")){String token=h.substring(7);if(jwt.valid(token)&&SecurityContextHolder.getContext().getAuthentication()==null){Long id=jwt.userId(token); UserPrincipal p=(UserPrincipal)users.loadUserByUsername(jwt.username(token)); if(p.id().equals(id)){var auth=new UsernamePasswordAuthenticationToken(p,null,p.getAuthorities());auth.setDetails(new WebAuthenticationDetailsSource().buildDetails(req));SecurityContextHolder.getContext().setAuthentication(auth);}}} chain.doFilter(req,res);}
}
